!(function (e) {
  "use strict";

  // Smooth scroll for anchor links (remains the same)
  e('a.js-scroll-trigger[href*="#"]:not([href="#"])').click(function () {
    if (
      location.pathname.replace(/^\//, "") ==
        this.pathname.replace(/^\//, "") &&
      location.hostname == this.hostname
    ) {
      var a = e(this.hash);
      if ((a = a.length ? a : e("[name=" + this.hash.slice(1) + "]")).length)
        return (
          e("html, body").animate(
            { scrollTop: a.offset().top - 54 },
            1e3,
            "easeInOutExpo"
          ),
          !1
        );
    }
  });

  // Closes responsive menu when a scroll trigger link is clicked (remains the same)
  e(".js-scroll-trigger").click(function () {
    e(".navbar-collapse").collapse("hide");
  });

  // Activate scrollspy to add active class to navbar items on scroll (remains the same)
  e("body").scrollspy({ target: "#mainNav", offset: 56 });

  // --- NEW: IntersectionObserver for Navbar Shrink ---
  var sentinel = document.querySelector("#navbar-sentinel");
  var mainNav = document.querySelector("#mainNav");

  var observer = new IntersectionObserver(
    function (entries) {
      if (entries[0].isIntersecting) {
        mainNav.classList.remove("navbar-shrink");
      } else {
        mainNav.classList.add("navbar-shrink");
      }
    },
    { threshold: [0] }
  );

  if (sentinel) {
    observer.observe(sentinel);
  }

  // --- NEW: IntersectionObserver for Staggered Scroll-Reveal ---
  var revealElements = document.querySelectorAll("#what-we-treat .card, .topic, .service-tier-card, .faq-card, .handwritten-accent");
  
  if (revealElements.length > 0 && 'IntersectionObserver' in window) {
    var revealObserver = new IntersectionObserver(
      function (entries, obs) {
        entries.forEach(function (entry) {
          if (entry.isIntersecting) {
            entry.target.classList.add("is-visible");
            obs.unobserve(entry.target);
          }
        });
      },
      { threshold: 0.15 }
    );

    revealElements.forEach(function (el, index) {
      el.classList.add("js-reveal");
      // Apply a dynamic staggered delay based on order of appearance in their respective containers
      var delay = (index % 4) * 75; // 0ms, 75ms, 150ms, 225ms
      el.style.transitionDelay = delay + "ms";
      revealObserver.observe(el);
    });
  }
})(jQuery);
